import (
	"context"
	ledgeraccount "github.com/openmeterio/openmeter/openmeter/ledger/account"
	"github.com/openmeterio/openmeter/openmeter/ledger"
	"github.com/openmeterio/openmeter/pkg/currencyx"
)

func provisionSubAccount(ctx context.Context, svc ledgeraccount.Service, ns, accountID string) (ledger.SubAccount, error) {
	return svc.EnsureSubAccount(ctx, ledger.CreateSubAccountInput{
		Namespace: ns,
		AccountID: accountID,
		Route:     ledger.Route{Currency: currencyx.Code("USD")},
	})
}

import (
	"context"
	"github.com/openmeterio/openmeter/openmeter/ledger"
	"github.com/openmeterio/openmeter/openmeter/ledger/historical"
)

func commit(ctx context.Context, l *historical.Ledger, group ledger.TransactionGroupInput) (ledger.TransactionGroup, error) {
	// CommitGroup: validates entries via routingValidator, locks customer accounts,
	// creates transaction group row, books each transaction inside one transaction.Run
	return l.CommitGroup(ctx, group)
}

import (
	"github.com/openmeterio/openmeter/openmeter/ledger/resolvers"
)

// In app/common/customer.go (credits-enabled path only):
hook, err := resolvers.NewCustomerLedgerHook(resolvers.CustomerLedgerHookConfig{
	Service: accountResolver,
	Tracer:  tracer,
})
if err != nil { return err }
customerService.RegisterHooks(hook)

// In app/common/namespace.go:
ns.RegisterHandler(resolvers.NewNamespaceHandler(accountResolver))

import (
	"context"
	"github.com/openmeterio/openmeter/openmeter/ledger/transactions"
	"github.com/openmeterio/openmeter/openmeter/ledger"
	"github.com/openmeterio/openmeter/pkg/currencyx"
)

func issueReceivable(ctx context.Context, deps transactions.ResolverDependencies, customerID ledger.CustomerID, amount alpacadecimal.Decimal) error {
	txInputs, err := transactions.ResolveTransactions(ctx, deps, customerID,
		transactions.IssueCustomerReceivableTemplate{At: time.Now(), Currency: currencyx.Code("USD"), Amount: amount},
	)
	if err != nil { return err }
	_, err = historicalLedger.CommitGroup(ctx, transactions.GroupInputs(customerID.Namespace, txInputs...))
	return err
}
